<template>
	<div class="capacity-planning-header bg-white border-b border-gray-200 mb-4 py-3 space-y-3">
		<!-- Row 1: Week navigation -->
		<div class="flex items-center justify-between gap-2">
			<button
				@click="emit('week-change', 'prev')"
				class="px-2 py-1.5 border rounded hover:bg-gray-100 text-sm whitespace-nowrap"
				:title="translate('Previous week')"
			>
				← <span class="hidden sm:inline">{{ translate("Previous") }}</span>
			</button>

			<div class="text-sm sm:text-base font-semibold text-center whitespace-nowrap">
				{{ weekLabel }}
			</div>

			<div class="flex items-center gap-2">
				<button
					@click="emit('week-change', 'today')"
					class="px-2 py-1.5 border rounded hover:bg-gray-100 text-sm whitespace-nowrap"
					:title="translate('Current week')"
				>
					{{ translate("Today") }}
				</button>

				<button
					@click="emit('week-change', 'next')"
					class="px-2 py-1.5 border rounded hover:bg-gray-100 text-sm whitespace-nowrap"
					:title="translate('Next week')"
				>
					<span class="hidden sm:inline">{{ translate("Next") }}</span> →
				</button>
			</div>
		</div>

		<!-- Row 2: Filters (manager only) -->
		<div class="flex items-center gap-2">
			<input
				v-if="!store.isProjectUser"
				type="text"
				:placeholder="translate('Filter: employee...')"
				class="flex-1 px-2 py-1.5 border rounded text-sm min-w-0"
				:value="store.selectedEmployee || ''"
				@input="handleEmployeeFilter"
			/>

			<button
				@click="emit('refresh')"
				class="px-2 py-1.5 border rounded hover:bg-gray-100 text-sm flex-shrink-0"
				:title="translate('Refresh')"
			>
				🔄
			</button>
		</div>
	</div>
</template>

<script setup>
import { computed } from "vue";
import { useCapacityPlanningStore } from "../../stores/capacityPlanningStore";

const realWindow = typeof globalThis !== "undefined" ? globalThis.window : undefined;
const translate = (text) => {
	return typeof realWindow !== "undefined" && typeof realWindow.__ === "function"
		? realWindow.__(text)
		: text;
};

const emit = defineEmits(["week-change", "filter-change", "refresh"]);
const store = useCapacityPlanningStore();

const weekLabel = computed(() => {
	if (!store.currentWeekStart) return "";

	const start = new Date(store.currentWeekStart);
	const end = new Date(start);
	end.setDate(end.getDate() + 4); // Friday

	const startStr = start.toLocaleDateString("pl-PL", { month: "long", day: "numeric" });
	const endStr = end.toLocaleDateString("pl-PL", { month: "long", day: "numeric" });

	return `${startStr} - ${endStr}`;
});

function handleEmployeeFilter(event) {
	const value = event.target.value || null;
	store.selectedEmployee = value;
}
</script>
