<template>
	<div
		class="project-chip group relative flex items-center justify-between gap-1 px-2 py-1 rounded-full text-xs bg-indigo-100 text-indigo-700 border border-indigo-200 hover:bg-indigo-200 transition-colors"
		:class="readonly ? 'cursor-default' : 'cursor-pointer'"
		:title="readonly ? tooltipText : tooltipText + ' — kliknij aby edytować'"
		@click.stop="!readonly && emit('edit', entry)"
	>
		<span class="truncate max-w-[60px] sm:max-w-[100px]">{{ entry.project_name }}</span>
		<span class="font-semibold whitespace-nowrap">{{ entry.hours_per_day }}h</span>

		<!-- Delete button — visible on hover, hidden in readonly mode -->
		<button
			v-if="!readonly"
			class="ml-1 -mr-1 opacity-0 group-hover:opacity-100 transition-opacity w-4 h-4 flex items-center justify-center rounded-full hover:bg-red-200 hover:text-red-700 text-indigo-500"
			title="Usuń przypisanie"
			@click.stop="emit('delete', entry.assignment_name)"
		>
			×
		</button>
	</div>
</template>

<script setup>
import { computed } from "vue";

const props = defineProps({
	entry: {
		type: Object,
		required: true,
		// { assignment_name, project, project_name, hours_per_day }
	},
	readonly: { type: Boolean, default: false },
});

const emit = defineEmits(["edit", "delete"]);

const tooltipText = computed(
	() => `${props.entry.project_name}: ${props.entry.hours_per_day}h/dzień`
);
</script>
